var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"감히 왕의 병사들을 해하다니......","JPN":"よくも王の兵士を殺めたな……","ENG":"How dare you harm the royal troops of the Queen?","TWN":"竟敢殺害王的士兵……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"참으로 불경스럽기 짝이 없는 미물들이로다.","JPN":"実に不敬な虫けらである。","ENG":"Such insolent, petty worms.","TWN":"真是群不敬至極的廢物。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"너희에게는 내가 몸소 가장 고통스러운 천만 번의 재조립을 경험하게 하겠노라.","JPN":"貴様たちには余が自ら、最も苦痛に満ちた一千万回の再構築を経験させてやろう。","ENG":"I shall personally make you suffer the agony of a billion reassemblies...","TWN":"我要親自讓你們體驗最為痛苦，歷經上萬次的重組。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"멈춰.","JPN":"止まれ。","ENG":"Enough.","TWN":"住手。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"......또 다른 미물이로구나.","JPN":"……他にも虫けらがいたか。","ENG":"Yet another petty worm.","TWN":"……又一個廢物呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"감히 내 앞을 가로막은 대가가 무엇인지 알고는 있느냐?","JPN":"余の前に立った罪を償ってもらおう。","ENG":"Do you know the price of daring to stand in my way?","TWN":"妳知道阻擋我的代價是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 건 내가 알 바 아니지.","JPN":"そんなの知ったこっちゃない。","ENG":"I couldn't care less.","TWN":"那種事我才不管。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내게 중요한 건, 오랫동안 길을 잃고 헤매던 친구가 출구 앞에 서 있다는 것뿐이야.","JPN":"私にとって大事なのは、長きにわたって道に迷っていた友人が\\n出口の前に立ってるということだけ。","ENG":"What's important to me is that a friend who's been lost for ages is now standing in front of the exit.","TWN":"對我來說，最重要的是，一位長久以來不斷迷路的朋友，現在正站在迷宮的出口前。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 너 따위가 방해하게 내버려 둘 수는 없어.","JPN":"あんたなんかに邪魔させてたまるか。","ENG":"So I can't let some jerk like you stand in the way.","TWN":"所以我不會讓你這種東西妨礙她的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"실성이라도 한 것인가. 미물이여.","JPN":"正気の沙汰ではないな、虫けらが。","ENG":"Have you lost your mind, worm?","TWN":"妳是不是瘋了啊，廢物。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"혹은......","JPN":"それとも……","ENG":"Or...","TWN":"還是說……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"네 그 하찮은 카운터 워치의 힘을 믿고 패악을 저지르려 하는 것이냐?","JPN":"そのみすぼらしいカウンターウォッチを頼りに、\\n愚行を働こうとしているのか？","ENG":"Are you so confident in the power of your petty Counter Watch that you would commit such foolery?","TWN":"妳是仗著區區制裁者能量環的力量，才會這麼不自量力嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"너를 만 갈래로 조각내기 전에 자비를 베풀어, 네가 지금 누구와 마주했는지 가르쳐 주마.","JPN":"貴様を八つ裂きにする前に、貴様が誰に刃を向けているのか教えてやろう。","ENG":"Before I tear you apart into a million pieces, I shall be merciful and grant you knowledge of whom you dare to challenge.","TWN":"在將妳碎屍萬段之前，我就大發慈悲地告訴妳，妳所面對的是什麼樣的存在。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"나의 이름은 솔리키타티오.","JPN":"余の名はソリキタティオ。","ENG":"My name is Sollicitatio.","TWN":"我的名字是索爾奇塔提奧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"위대하신 마왕, 타기리온의 명을 받드는 첫 번째 사도이며......","JPN":"偉大なる魔王、タギリオン様の第一使徒であり……","ENG":"I am the first apostle of the great Demon Lord Thagirion.","TWN":"是信奉偉大的魔王——塔基里翁的最初使徒……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너희 하찮은 미물들이 5종이라 칭하는 절대적인 존재이다.","JPN":"貴様たちのような塵芥が第5種と称する絶対的存在だ。","ENG":"I am an absolute being, which you worms call Category 5.","TWN":"是被你們這些卑劣的廢物稱之為5類的絕對存在。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 뭐? 신비한 5종 침식체를 만났다고 환호라도 해 줄까?","JPN":"それがどうした？\\n珍しい第5種侵食体に会えたって、歓喜の声でも上げるべき？","ENG":"So what? Am I supposed to cheer because I came across a fantastic Category 5 C.O.?","TWN":"所以怎麼？妳要我因為見到了罕見的5類侵蝕體歡呼嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"동물원 같은 곳에 가둬 두면 인기는 끌겠군.","JPN":"動物園とかに放り込めば、人気は出そうだ。","ENG":"I guess you'd be a riot in a zoo somewhere.","TWN":"把你關進動物園中應該會很受歡迎吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"한 가지 가르쳐 주지.","JPN":"一つ教えてやる。","ENG":"Let me tell you something.","TWN":"我來告訴你一件事吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 인간은 4종 이상의 침식체를 상대할 수 없어.","JPN":"そもそも、人間は第4種以上の侵食体には敵わない。","ENG":"Humans aren't capable of facing off anything above Category 4 in the first place.","TWN":"本來，人類是無法對抗4類以上的侵蝕體的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 현실은 그렇게 단순한 수치 대결만으로 결정되지 않아.","JPN":"だけど実際は、そんな単純な数値の小競り合いだけで物事は決まらない。","ENG":"But reality isn't all about numbers and categories.","TWN":"但現實卻不是用單純的數值對決所決定的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 네 녀석이 당장 여기서 꺼지지 않겠다면......","JPN":"あんたがここを去らないと言うなら……","ENG":"Which means, unless you get out of my face this instant...","TWN":"所以如果你不馬上從這裡消失……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"구 관리국 최강의 에이스라는 말이 어떤 뜻인지, 확실히 느끼게 해 주지.","JPN":"旧管理局最強のエースという呼び名の意味を、\\n身をもって体験させてあげましょう。","ENG":"I'll make sure you get a taste of what the ace of the Old Administration is capable of.","TWN":"《舊管理局最強王牌》這是什麼意思，我就讓你切身感受一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"용납할 수 없는 폭언이로다......!","JPN":"忌々しい奴め……！","ENG":"Such unforgivable insolence!","TWN":"大言不慚……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 무도한 태도에 책임을 져야 할 것이다, 미물이여!","JPN":"虫けらよ、その傲慢な態度を悔い改めるがよい！","ENG":"You shall pay for your impudence, worm!","TWN":"為妳狂妄的態度負責吧，廢物！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};